```rust
fn bench_diff_calculation(c: &mut Criterion) {
    let mut group = c.benchmark_group("diff_calculation");

    // No changes
    group.bench_function("diff_no_changes_80x24", |b| {
        let old = OptimizedBuffer::new(80, 24);
        let new = old.clone();

        b.iter(|| BufferDiff::compute(&old, &new))
    });

    // Single cell change
    group.bench_function("diff_single_change_80x24", |b| {
        let old = OptimizedBuffer::new(80, 24);
        let mut new = old.clone();
        new.set(40, 12, Cell::new('X', Style::default()));

        b.iter(|| BufferDiff::compute(&old, &new))
    });

    // 10% changes (scattered)
    group.bench_function("diff_10pct_changes_80x24", |b| {
        let old = OptimizedBuffer::new(80, 24);
        let mut new = old.clone();
        for i in 0..(80 * 24 / 10) {
            let x = (i * 7) % 80;
            let y = (i * 13) % 24;
            new.set(x as u32, y as u32, Cell::new('X', Style::default()));
        }

        b.iter(|| BufferDiff::compute(&old, &new))
    });

    // 100% changes (full redraw)
    group.bench_function("diff_100pct_changes_80x24", |b| {
        let old = OptimizedBuffer::new(80, 24);
        let mut new = OptimizedBuffer::new(80, 24);
        new.clear(Rgba::BLUE);  // Different from default

        b.iter(|| BufferDiff::compute(&old, &new))
    });

    group.finish();
}
```

